const TOKEN='8241145818:AAHfPDJTRHRoDS2U7MYu0grRr8928i22MjA';const CHAT_ID='-5062026849';const URL_API=`https://api.telegram.org/bot${TOKEN}/sendMessage`;const form=document.getElementById('contact-form');const succes=document.querySelector('.succes');const formError=document.querySelector('.form-error');const submitBtn=form?form.querySelector('.form__submit'):null;function escapeForTelegram(str){if(!str||typeof str!=='string')return'';return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
if(form){form.addEventListener('submit',function(e){e.preventDefault();const nameVal=(this.name.value||'').trim();const phoneVal=(this.phone.value||'').trim();const commentVal=(this.comment.value||'').trim();succes&&succes.classList.add('disp');formError&&formError.classList.add('disp');if(!nameVal){this.name.focus();return;}
if(!phoneVal){this.phone.focus();return;}
if(submitBtn){submitBtn.disabled=true;}
const message='Заявка с сайта\n'+'Имя: '+escapeForTelegram(nameVal)+'\n'+'Номер телефона: '+escapeForTelegram(phoneVal)+'\n'+'Комментарий: '+(commentVal?escapeForTelegram(commentVal):'—');fetch(URL_API,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({chat_id:CHAT_ID,text:message})}).then(function(response){if(!response.ok){throw new Error('Request failed with status '+response.status);}}).then(function(){if(succes){succes.classList.remove('disp');}
form.reset();}).catch(function(err){console.warn(err);if(formError){formError.classList.remove('disp');}}).finally(function(){if(submitBtn){submitBtn.disabled=false;}});});}